using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

builder.Services.AddSingleton<ModelTrainingService>();

// Train the model at startup via a hosted service
builder.Services.AddHostedService<ModelTrainingHostedService>();

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

/// <summary>Trains the ML model once at application startup.</summary>
internal sealed class ModelTrainingHostedService(ModelTrainingService trainer) : IHostedLifecycleService
{
    // Train during StartingAsync so the model file exists before the app accepts requests.
    public Task StartingAsync(CancellationToken cancellationToken)
    {
        trainer.TrainAndEvaluate();
        return Task.CompletedTask;
    }

    public Task StartAsync(CancellationToken cancellationToken) => Task.CompletedTask;
    public Task StartedAsync(CancellationToken cancellationToken) => Task.CompletedTask;
    public Task StoppingAsync(CancellationToken cancellationToken) => Task.CompletedTask;
    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
    public Task StoppedAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

